// TC-016: Worker Single Pane and Server-Managed Work
//
// workers-single-pane.spec.ts covers TC-016.1, TC-016.2, and the federation
// listing fixture (TC-016 federation row from US-100). All tests use static
// fixture data and mocked GraphQL routes — no live developer DDx state is
// required. These tests pass once the /nodes/:nodeId/workers route and
// node-wide workers query land (implementation beads).

import { expect, test } from '@playwright/test';

// Static fixture identifiers — no live server request is made.
const NODE_ID = 'node-test-singlePane';
const NODE_NAME = 'test-node-singlePane';

const PROJECT_ALPHA = { id: 'project-alpha', name: 'Project Alpha', path: '/tmp/project-alpha' };
const PROJECT_BETA = { id: 'project-beta', name: 'Project Beta', path: '/tmp/project-beta' };

// Workers from two different local projects, each with a project badge.
const WORKERS_MULTI_PROJECT = [
	{
		id: 'worker-aaaaaaaa',
		kind: 'execute-bead',
		state: 'running',
		status: 'processing',
		harness: 'claude',
		model: 'claude-sonnet-4-6',
		currentBead: 'bead-alpha-001',
		attempts: 3,
		successes: 2,
		failures: 1,
		startedAt: '2026-06-01T10:00:00Z',
		projectId: PROJECT_ALPHA.id,
		projectName: PROJECT_ALPHA.name
	},
	{
		id: 'worker-bbbbbbbb',
		kind: 'work',
		state: 'idle',
		status: null,
		harness: 'claude',
		model: 'claude-sonnet-4-6',
		currentBead: null,
		attempts: 5,
		successes: 5,
		failures: 0,
		startedAt: '2026-06-01T09:00:00Z',
		projectId: PROJECT_BETA.id,
		projectName: PROJECT_BETA.name
	}
];

// Worker detail fixture for the running worker.
const WORKER_DETAIL_ALPHA = {
	id: 'worker-aaaaaaaa',
	kind: 'execute-bead',
	state: 'running',
	status: 'processing',
	harness: 'claude',
	model: 'claude-sonnet-4-6',
	effort: 'normal',
	once: false,
	pollInterval: '30s',
	startedAt: '2026-06-01T10:00:00Z',
	finishedAt: null,
	currentBead: 'bead-alpha-001',
	lastError: null,
	attempts: 3,
	successes: 2,
	failures: 1,
	currentAttempt: {
		attemptId: 'attempt-alpha-001',
		beadId: 'bead-alpha-001',
		phase: 'executing',
		startedAt: '2026-06-01T10:05:00Z',
		elapsedMs: 45000
	},
	recentEvents: [],
	lifecycleEvents: []
};

const WORKER_LOG_ALPHA = {
	stdout: 'Booting agent harness...\nReading bead spec.\nDone.',
	stderr: ''
};

// Hub worker (from hub node) and spoke worker (from spoke node) for federation fixture.
const HUB_WORKER = {
	id: 'worker-hub-aaaaaaaa',
	kind: 'work',
	state: 'running',
	status: 'running',
	harness: 'claude',
	model: 'claude-sonnet-4-6',
	currentBead: 'bead-hub-001',
	attempts: 1,
	successes: 0,
	failures: 0,
	startedAt: '2026-06-01T10:00:00Z',
	nodeId: NODE_ID,
	nodeName: NODE_NAME
};

const SPOKE_NODE_ID = 'node-spoke-federation';
const SPOKE_WORKER = {
	id: 'worker-spoke-bbbbbbbb',
	kind: 'execute-bead',
	state: 'idle',
	status: null,
	harness: 'claude',
	model: 'claude-opus-4-8',
	currentBead: null,
	attempts: 2,
	successes: 2,
	failures: 0,
	startedAt: '2026-06-01T08:00:00Z',
	nodeId: SPOKE_NODE_ID,
	nodeName: 'spoke-node'
};

function makeWorkersResponse(workers: Record<string, unknown>[]) {
	return {
		workers: {
			edges: workers.map((w, i) => ({ node: w, cursor: `cursor-${i}` })),
			pageInfo: { hasNextPage: false, endCursor: null },
			totalCount: workers.length
		}
	};
}

function makeFederationWorkersResponse(workers: Record<string, unknown>[]) {
	return {
		federatedWorkers: {
			edges: workers.map((w, i) => ({ node: w, cursor: `cursor-${i}` })),
			pageInfo: { hasNextPage: false, endCursor: null },
			totalCount: workers.length
		}
	};
}

async function mockNodeWideGraphQL(
	page: import('@playwright/test').Page,
	workers: Record<string, unknown>[] = WORKERS_MULTI_PROJECT
) {
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as { query: string };

		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: { id: NODE_ID, name: NODE_NAME } } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						projects: {
							edges: [PROJECT_ALPHA, PROJECT_BETA].map((p) => ({ node: p }))
						}
					}
				})
			});
		} else if (body.query.includes('WorkersByProject') || body.query.includes('workersByProject')) {
			// Node-wide page may still use workersByProject per-project; pass all workers.
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeWorkersResponse(workers) })
			});
		} else if (
			body.query.includes('Workers') &&
			!body.query.includes('WorkerDetail') &&
			!body.query.includes('WorkerLog') &&
			!body.query.includes('WorkerProgress')
		) {
			// Node-wide `workers` query (no projectID argument).
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeWorkersResponse(workers) })
			});
		} else if (body.query.includes('WorkerDetail') || (body.query.includes('worker(') || body.query.includes('Worker('))) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { worker: WORKER_DETAIL_ALPHA } })
			});
		} else if (body.query.includes('WorkerLog') || body.query.includes('workerLog')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { workerLog: WORKER_LOG_ALPHA } })
			});
		} else if (body.query.includes('federation') || body.query.includes('Federation') || body.query.includes('federatedWorkers')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeFederationWorkersResponse([HUB_WORKER, SPOKE_WORKER]) })
			});
		} else {
			await route.continue();
		}
	});
}

// TC-016.1 — node-wide workers single pane shows workers from multiple projects.
test('shows all local project workers in one node-wide pane', async ({ page }) => {
	await mockNodeWideGraphQL(page);
	await page.goto(`/nodes/${NODE_ID}/workers`);

	// The page heading should identify the workers workbench.
	await expect(page.getByRole('heading', { name: 'Workers', exact: true })).toBeVisible();

	// Both workers from different projects must be visible.
	// Worker from Project Alpha (running execute-bead).
	await expect(page.getByText('worker-a').first()).toBeVisible();
	// Worker from Project Beta (idle work).
	await expect(page.getByText('worker-b').first()).toBeVisible();

	// Project badges for both projects must appear.
	await expect(page.getByText(PROJECT_ALPHA.name).first()).toBeVisible();
	await expect(page.getByText(PROJECT_BETA.name).first()).toBeVisible();

	// States must be represented.
	await expect(page.getByText('running')).toBeVisible();
	await expect(page.getByText('idle')).toBeVisible();

	// Total count reflects both workers.
	await expect(page.getByText(/2 total/)).toBeVisible();

	// Current bead id should be visible for the running worker.
	await expect(page.getByText('bead-alpha-001').first()).toBeVisible();
});

// TC-016.2 — worker detail shows current bead, phase, captured output, and prompt.
test('opens worker detail with current bead and captured output', async ({ page }) => {
	await mockNodeWideGraphQL(page);
	await page.goto(`/nodes/${NODE_ID}/workers`);

	// Click the running worker row to open the detail panel.
	await page.getByText('running').first().click();

	// URL must include the worker id.
	await expect(page).toHaveURL(/\/workers\/worker-aaaaaaaa/);

	// Detail panel: current bead link must be present.
	await expect(page.getByText('bead-alpha-001').first()).toBeVisible();

	// Current phase from currentAttempt.
	await expect(page.getByText('executing')).toBeVisible();

	// Captured output from workerLog.stdout must appear.
	await expect(page.getByText('Booting agent harness...')).toBeVisible();

	// Stop action must be available for a running worker.
	await expect(page.getByRole('button', { name: 'Stop' })).toBeVisible();
});

// TC-016: Worker Single Pane and Server-Managed Work
//
// workers-dispatch.spec.ts covers TC-016.3, TC-016.4, and TC-016.5 from
// TP-002 (starts two workers, refuses beyond max_count, stop with lifecycle
// event). All tests use static fixture data and mocked GraphQL routes — no
// live developer DDx state is required. Tests pass once the implementation
// beads for server-managed dispatch land.

import { expect, test } from '@playwright/test';

// Static fixture identifiers — no live server request is made.
const NODE_ID = 'node-test-dispatch';
const NODE_NAME = 'test-node-dispatch';
const PROJECT_ID = 'project-dispatch-001';
const PROJECT = { id: PROJECT_ID, name: 'Dispatch Project', path: '/tmp/project-dispatch' };

// Base URL for the project workers page where dispatch controls live.
const BASE_URL = `/nodes/${NODE_ID}/projects/${PROJECT_ID}/workers`;

function makeBaseWorker(overrides: Record<string, unknown> = {}): Record<string, unknown> {
	return {
		id: 'worker-placeholder',
		kind: 'work',
		state: 'running',
		status: 'running',
		harness: 'claude',
		model: null,
		currentBead: null,
		attempts: 0,
		successes: 0,
		failures: 0,
		startedAt: '2026-06-01T10:00:00Z',
		...overrides
	};
}

function makeWorkersResponse(
	workers: Record<string, unknown>[],
	maxCount: number | null = null
) {
	return {
		workersByProject: {
			edges: workers.map((w, i) => ({ node: w, cursor: `cursor-${i}` })),
			pageInfo: { hasNextPage: false, endCursor: null },
			totalCount: workers.length
		},
		queueAndWorkersSummary: { maxCount }
	};
}

function makeSessionsResponse() {
	return {
		agentSessions: {
			edges: [],
			pageInfo: { hasNextPage: false, endCursor: null },
			totalCount: 0
		},
		sessionsCostSummary: {
			cashUsd: 0,
			subscriptionEquivUsd: 0,
			localSessionCount: 0,
			localEstimatedUsd: 0
		}
	};
}

// TC-016.3 — starts two server-managed work workers and both rows appear.
test('starts two server managed work workers', async ({ page }) => {
	let workers: Record<string, unknown>[] = [];
	let startCallCount = 0;
	const startInputs: Array<Record<string, unknown>> = [];

	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as {
			query: string;
			variables?: Record<string, unknown>;
		};

		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: { id: NODE_ID, name: NODE_NAME } } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: [PROJECT].map((p) => ({ node: p })) } }
				})
			});
		} else if (body.query.includes('WorkersByProject') || body.query.includes('workersByProject')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeWorkersResponse(workers) })
			});
		} else if (body.query.includes('StartWorker') || body.query.includes('startWorker')) {
			startCallCount++;
			startInputs.push((body.variables?.input ?? {}) as Record<string, unknown>);
			const newWorker = makeBaseWorker({
				id: `worker-dispatch-${startCallCount.toString().padStart(8, '0')}`,
				kind: 'work',
				state: 'running',
				status: 'running'
			});
			workers = [newWorker, ...workers];
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						startWorker: {
							id: newWorker.id,
							state: newWorker.state,
							kind: newWorker.kind
						}
					}
				})
			});
		} else if (body.query.includes('QueueAndWorkersSummary') || body.query.includes('queueAndWorkersSummary')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						queueAndWorkersSummary: {
							readyBeads: 5,
							runningWorkers: workers.filter((w) => w.state === 'running').length,
							totalWorkers: workers.length,
							maxCount: null
						}
					}
				})
			});
		} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeSessionsResponse() })
			});
		} else {
			await route.continue();
		}
	});

	await page.goto(BASE_URL);
	await expect(page.getByRole('heading', { name: 'Workers', exact: true })).toBeVisible();

	// Initial state: no workers.
	await expect(page.getByText('0 total')).toBeVisible();

	// Start first worker.
	await page.getByRole('button', { name: 'Start worker' }).click();
	await page.getByRole('button', { name: 'Start', exact: true }).click();
	await expect.poll(() => startCallCount, { timeout: 3000 }).toBe(1);
	expect(startInputs[0]).toMatchObject({ projectId: PROJECT_ID, requestTimeout: '20m' });

	// Reload or await re-query: first worker row appears.
	await expect(page.getByText('worker-d').first()).toBeVisible();
	await expect(page.getByText('1 total')).toBeVisible();

	// Start second worker.
	await page.getByRole('button', { name: 'Start worker' }).click();
	await page.getByRole('button', { name: 'Start', exact: true }).click();
	await expect.poll(() => startCallCount, { timeout: 3000 }).toBe(2);
	expect(startInputs[1]).toMatchObject({ projectId: PROJECT_ID, requestTimeout: '20m' });

	// Both worker rows must appear.
	await expect(page.getByText('2 total')).toBeVisible();
	await expect(page.getByText('running').first()).toBeVisible();
});

// TC-016.4 — refuses starts beyond workers.max_count.
test('refuses starts beyond workers max count', async ({ page }) => {
	// One worker already running, cap is 1.
	const cappedWorker = makeBaseWorker({ id: 'worker-capped-00000001', state: 'running' });

	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as { query: string };

		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: { id: NODE_ID, name: NODE_NAME } } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: [PROJECT].map((p) => ({ node: p })) } }
				})
			});
		} else if (body.query.includes('WorkersByProject') || body.query.includes('workersByProject')) {
			// Return capped state: 1 running worker, maxCount=1.
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeWorkersResponse([cappedWorker], 1) })
			});
		} else if (body.query.includes('QueueAndWorkersSummary') || body.query.includes('queueAndWorkersSummary')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						queueAndWorkersSummary: {
							readyBeads: 2,
							runningWorkers: 1,
							totalWorkers: 1,
							maxCount: 1
						}
					}
				})
			});
		} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeSessionsResponse() })
			});
		} else {
			await route.continue();
		}
	});

	await page.goto(BASE_URL);
	await expect(page.getByRole('heading', { name: 'Workers', exact: true })).toBeVisible();

	// The add-drain-worker button (+ Add worker) must be disabled at the cap.
	const addBtn = page.getByTestId('add-drain-worker');
	await expect(addBtn).toBeVisible();
	await expect(addBtn).toBeDisabled();

	// The disabled state must convey the cap reason to the operator.
	await expect(addBtn).toHaveAttribute('title', 'at workers.max_count limit');

	// The start-worker button in the dialog path also reflects the cap.
	// If the button isn't present (only the count-panel button is shown),
	// verifying the add button disabled + title is sufficient coverage for the cap AC.
	await expect(page.getByText(/1 total/)).toBeVisible();
});

// TC-016.5 — stops a running worker and shows the lifecycle event in the detail panel.
test('stops a worker and shows the lifecycle event', async ({ page }) => {
	let workerState = 'running';
	let stopCalled = false;

	const LIFECYCLE_EVENTS_AFTER_STOP = [
		{
			action: 'start',
			actor: 'local-operator',
			timestamp: '2026-06-01T10:00:00Z',
			detail: 'profile=smart effort=medium',
			beadId: null
		},
		{

			action: 'stop',
			actor: 'local-operator',
			timestamp: '2026-06-01T10:05:00Z',
			detail: 'reason=operator-stop',
			beadId: null
		}
	];

	const WORKER_ID = 'worker-lifecycle-00000001';

	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as {
			query: string;
			variables?: Record<string, unknown>;
		};

		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: { id: NODE_ID, name: NODE_NAME } } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: [PROJECT].map((p) => ({ node: p })) } }
				})
			});
		} else if (body.query.includes('WorkersByProject') || body.query.includes('workersByProject')) {
			const w = makeBaseWorker({ id: WORKER_ID, state: workerState, status: workerState });
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeWorkersResponse([w]) })
			});
		} else if (body.query.includes('StopWorker') || body.query.includes('stopWorker')) {
			stopCalled = true;
			workerState = 'stopped';
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						stopWorker: { id: WORKER_ID, state: 'stopped', kind: 'work' }
					}
				})
			});
		} else if (body.query.includes('WorkerDetail') || body.query.includes('worker(') || body.query.includes('Worker(')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						worker: {
							id: WORKER_ID,
							kind: 'work',
							state: workerState,
							status: workerState,
							harness: 'claude',
							model: null,
							effort: 'medium',
							once: false,
							pollInterval: '30s',
							startedAt: '2026-06-01T10:00:00Z',
							finishedAt: workerState === 'stopped' ? '2026-06-01T10:05:00Z' : null,
							currentBead: null,
							lastError: null,
							attempts: 0,
							successes: 0,
							failures: 0,
							currentAttempt: null,
							recentEvents: [],
							lifecycleEvents: stopCalled ? LIFECYCLE_EVENTS_AFTER_STOP : [LIFECYCLE_EVENTS_AFTER_STOP[0]]
						}
					}
				})
			});
		} else if (body.query.includes('WorkerLog') || body.query.includes('workerLog')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { workerLog: { stdout: '', stderr: '' } } })
			});
		} else if (body.query.includes('QueueAndWorkersSummary') || body.query.includes('queueAndWorkersSummary')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						queueAndWorkersSummary: {
							readyBeads: 1,
							runningWorkers: workerState === 'running' ? 1 : 0,
							totalWorkers: 1,
							maxCount: null
						}
					}
				})
			});
		} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeSessionsResponse() })
			});
		} else {
			await route.continue();
		}
	});

	await page.goto(BASE_URL);
	await expect(page.getByRole('heading', { name: 'Workers', exact: true })).toBeVisible();

	// Running worker row must be present.
	await expect(page.getByText('running')).toBeVisible();

	// Navigate to the worker detail panel.
	await page.goto(`${BASE_URL}/${WORKER_ID}`);

	// Stop button must be visible for a running worker.
	const stopBtn = page.getByRole('button', { name: 'Stop' });
	await expect(stopBtn).toBeVisible();

	// Accept the confirmation dialog that Stop opens.
	page.once('dialog', async (dialog) => {
		await dialog.accept();
	});
	await stopBtn.click();
	await expect.poll(() => stopCalled, { timeout: 3000 }).toBe(true);

	// Worker must reach a terminal state (stopped).
	await expect(page.getByText('stopped').first()).toBeVisible({ timeout: 5000 });

	// Lifecycle audit section must show the stop event.
	await expect(page.getByText('Lifecycle audit')).toBeVisible();
	await expect(page.getByText('stop')).toBeVisible();
	await expect(page.getByText('local-operator')).toBeVisible();
});

